#!/usr/bin/env node
/**
 * Walk every `*.service.ts` (and any other `@Injectable`) in the lib and
 * generate a single `_mocks/global-stub.providers.ts` file that registers
 * every service with `useValue: autoStub<TheService>()`.
 *
 * The generated file is wired into `.storybook/preview.ts`, so any auto-
 * generated stub story can render without crashing on missing DI.
 *
 * Hand-written stories that supply their own service stubs still work —
 * `applicationConfig({ providers: [...] })` at the story level overrides
 * the global stubs for that story.
 *
 * Run after a sync:
 *   npm run sync-source
 *   node scripts/generate-mock-providers.mjs
 *   npm run build-storybook
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, '..');
const LIB = path.join(REPO_ROOT, 'projects/extracted/src/lib');
const TARGET = path.join(LIB, '_mocks/global-stub.providers.ts');

function walk(dir) {
  const out = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    if (entry.name === 'node_modules' || entry.name.startsWith('.')) continue;
    if (entry.name === '_mocks') continue; // skip our own folder
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) out.push(...walk(full));
    else if (
      (entry.name.endsWith('.service.ts') ||
        entry.name === 'userActivity.ts') &&
      !entry.name.endsWith('.spec.ts')
    ) {
      out.push(full);
    }
  }
  return out;
}

const files = walk(LIB).sort();
const entries = [];
const seenClasses = new Set();

for (const file of files) {
  const content = fs.readFileSync(file, 'utf-8');
  // Find every `@Injectable` and the class name following it.
  // Pattern: @Injectable({...})\nexport (abstract )?class Foo<T>
  const re =
    /@Injectable[\s\S]*?export\s+(?:abstract\s+)?class\s+(\w+)(\s*<[^{]+>)?/g;
  let match;
  while ((match = re.exec(content)) !== null) {
    const className = match[1];
    const genericMatch = match[2];
    // Replace each generic param with `unknown` so the cast is valid.
    const generics = genericMatch
      ? `<${genericMatch
          .slice(1, -1)
          .split(',')
          .map(() => 'Record<string, unknown>')
          .join(', ')}>`
      : '';
    if (className.startsWith('_')) continue; // skip private convention
    // Skip date adapters (Angular Material's MAT_DATE_LOCALE expects specific
    // tokens, not class providers — these don't need stubbing).
    if (file.includes('custom-adapters/')) continue;
    // Auto-generated OpenAPI services have type issues unrelated to mocking;
    // the wrapping services components actually inject (DocumentService etc.)
    // are kept.
    if (file.includes('autogenerated/openapi/')) continue;
    if (seenClasses.has(className)) continue;
    seenClasses.add(className);

    const rel = path.relative(LIB, file).replace(/\.ts$/, '');
    const importPath = `../${rel}`;
    entries.push({ className, importPath, generics });
  }
}

// Sort by class name for stable output
entries.sort((a, b) => a.className.localeCompare(b.className));

const importLines = entries
  .map((e) => `import { ${e.className} } from '${e.importPath}';`)
  .join('\n');

const providerLines = entries
  .map(
    (e) =>
      // Cast through `unknown`. Generic services like `DataTableService<T>`
      // get `<unknown>` filled in for each type param so the cast is valid.
      `  { provide: ${e.className}, useValue: autoStub() as unknown as ${e.className}${e.generics} },`,
  )
  .join('\n');

const banner = `// AUTO-GENERATED by scripts/generate-mock-providers.mjs.
// Regenerate after \`npm run sync-source\` brings in new services.
// Do not hand-edit this file — write per-story service stubs in your
// .stories.ts instead, which override these global stubs for that story.

import { autoStub } from './auto-stub';
`;

const fileContent = `${banner}
${importLines}

export const GLOBAL_STUB_PROVIDERS = [
${providerLines}
];
`;

fs.mkdirSync(path.dirname(TARGET), { recursive: true });
fs.writeFileSync(TARGET, fileContent);

console.log(
  `Wrote ${entries.length} stubbed-service providers to ${path.relative(REPO_ROOT, TARGET)}`,
);
